I don't necessarily think that is the write or wrong way of doing things, as there are several ways of storing that information. seeing different solutions around, they range being part of the script, in a separate config file within the module, part of the main configuration file, or as part of the model. your implementation will depend on how flexible and/or portable you want the solution.

The only downside to storing it in the main settings.py is that when moving the module from your dev environment to your production environment or someone else imports the module, they/you will need to add the necessary to the settings.py.

Hi! This is my code for send vibration in gamepad in python (works with xbox 360 controller, dualshock 4, wii remote).
`import fcntl, struct, array, time
	
EVIOCRMFF = 0x40044581
EVIOCSFF = 0x40304580
LOG_CLASS_ON = False
TIME_DELTA = 250

class Vibrate:

    def __init__(self, file):
        self.ff_joy = open(file, "r+")

    def close(self):
        self.ff_joy.close()

    def new_effect(self, strong, weak, length):
        effect = struct.pack('HhHHHHHxHH', 0x50, -1, 0, 0, 0, length, 0, int(strong * 0xFFFF), int(weak * 0xFFFF))
        a = array.array('h', effect)
        fcntl.ioctl(self.ff_joy, EVIOCSFF, a, True)
        return a[1]
        id = a[1]
        return (ev_play, ev_stop)

    def play_efect(self, id):
        if type(id) == tuple or type(id) == list:
            ev_play = ''
            for i in id:
                ev_play = ev_play + struct.pack('LLHHi', 0, 0, 0x15, i, 1)
        else:
            ev_play = struct.pack('LLHHi', 0, 0, 0x15, id, 1)
        self.ff_joy.write(ev_play)
        self.ff_joy.flush()

    def stop_effect(self, id):
        if type(id) == tuple or type(id) == list:
            ev_stop = ''
            for i in id:
                ev_stop = ev_stop + struct.pack('LLHHi', 0, 0, 0x15, i, 0)
        else:
            ev_stop = struct.pack('LLHHi', 0, 0, 0x15, id, 0)
        self.ff_joy.write(ev_stop)
        self.ff_joy.flush()

    def forget_effect(self, id):
        if type(id) == tuple or type(id) == list:
            for i in id:
                fcntl.ioctl(self.ff_joy, EVIOCRMFF, i)
        else:
            fcntl.ioctl(self.ff_joy, EVIOCRMFF, id)

f = Vibrate("/dev/input/event14")
p = f.new_effect(1.0, 1.0, TIME_DELTA )
f.play_efect((p))
time.sleep(TIME_DELTA / 1000.0)
f.stop_effect((p))
f.forget_effect((p))`

```
class MaybeObject():
    def __init__(self, data):
        self.__data


class MaybeDescriptor(object):
    def __init__(self, *path, default=None):
        self.path = path
        self.default_value = default

    def __get__(self, instance, owner):
        maybe_value = maybe(instance)
        maybe_value = getattr(maybe_value, '__data')
        for p in self.path:
            maybe_value = getattr(maybe_value, p) or maybe_value[p]

        return maybe_value.or_else(self.default_value)


class YoutubeResponse(object):
    id = MaybeDescriptor('id')
    title = MaybeDescriptor('snippet', 'title')
    description = MaybeDescriptor('snippet', 'description', default='no description...')

```

