_PATH_FOR_WD {1: 'tmp'}
_WD_FOR_PATH {'tmp': 1}
READ_EVENTS 1 tmp tmp/a 1073742080 0 a
INOTIFY_EVENT <InotifyEvent: src_path=tmp/a, wd=1, mask=IN_CREATE|IN_ISDIR, cookie=0, name=a>
_PATH_FOR_WD {1: 'tmp', 2: 'tmp/a'}
_WD_FOR_PATH {'tmp': 1, 'tmp/a': 2}
READ_EVENTS 2 tmp/a tmp/a/b 1073742080 0 b
INOTIFY_EVENT <InotifyEvent: src_path=tmp/a/b, wd=2, mask=IN_CREATE|IN_ISDIR, cookie=0, name=b>
